float makePoint(vec2 p,float fx,float fy,float sx,float sy,float t)
{
//	vec2 z = p*sin(vec2(t,t)/vec2(fx, fy));
//	return 1.0 /(sqrt(length(z.x+z.y) + length(z.x*z.y)));
	float xx=p.x*cos(t/fx);
	float yy=p.y*sin(t/fy);
	return 1.0/ (sqrt(length(xx+yy) + length(xx*yy)));
}

