void main()
{
	vec2 p = si.tex*vec2(2.0)-vec2(1.0);
	float a = (atan(p.y,p.x)+PI)/PI2;
	float r = length(p); 

	//vec4 col = textureLod(gTexture1, vec2(a+gTime*0.1,a+gTime*0.1), 6.0)*gColor1*3.0;
	vec4 col = (_noise(vec2(a*50.0+gTime*0.1,a+gTime*0.1))*0.2+0.8)*gColor1*0.5;
	//vec4 col = vec4(_noise(vec2(a*10.0+gTime*0.1,a*10.0+gTime*0.1))*0.5+0.5);
	col.rgb *= 1.0/pow(r,gIn1.x);
	col.rgb *= vec3(smoothstep(2.0, 0.5, length(p)));
	oColor = col*col;
}
